function ChestOpened(p79, p80) -- name: ChestOpened
	-- upvalues: (copy) v_u_3, (copy) v_u_2, (copy) v_u_1
	if p79:GetAttribute("Locked") then
		if p79:GetAttribute("LockedMessage") then
			v_u_3.Events.SetPopUpMessage:Fire(p79:GetAttribute("LockedMessage"), "warning")
		end
		return
	elseif p79:GetAttribute("LocalOpened") then
		return
	else
		p79:SetAttribute("LocalOpened", true)
		local v81 = v_u_2.UserId
		p79:SetAttribute(math.abs(v81) .. "Opened", true)
		p79.PrimaryPart.ProximityAttachment:Destroy()
		p79:RemoveTag("Interaction")
		if p79:GetAttribute("ThanksgivingChest") then
			v_u_3.ThanksgivingChestClient.OpenChest(p79, p80)
			v_u_3.Sound.Play("LidReveal")
			return
		elseif p79:GetAttribute("ChristmasPresent") then
			v_u_3.ChristmasPresentClient.OpenChest(p79, p80)
			return
		elseif p79:GetAttribute("RandomBox") then
			v_u_3.GamblerChestClient.OpenChest(p79, p80)
			return
		elseif p79:HasTag("HardModeCrate") then
			v_u_3.ResearchOutpostClient.OpenCrate(p79, p80)
		else
			if not p80 then
				v_u_3.Sound.Play("ChestToggle")
				v_u_3.Events.RequestOpenItemChest:FireServer(p79)
				v_u_1.HasOpenedChest = true
				if v_u_3.TutorialClient.ChestTutorialActive then
					v_u_3.TutorialClient.ChestTutorialActive = false
					for _, v82 in pairs(v_u_3.MapDrawClient.TutorialCircles) do
						v82.Visible = false
					end
				end
			end
			local v83 = p79.ChestLid:GetPivot()
			p79.ChestLid:PivotTo(v83 * CFrame.Angles(-1.7453292519943295, 0, 0))
			if p79:FindFirstChild("Highlight") then
				p79.Highlight:Destroy()
			end
			if not p80 and (p79:FindFirstChild("Platform") and p79.Platform:FindFirstChild("BG")) then
				p79.Platform.BG:Emit(p79.Platform.BG:GetAttribute("EmitCount"))
				p79.Platform.Front:Emit(p79.Platform.Front:GetAttribute("EmitCount"))
				if v_u_2.Character and v_u_2.Character:FindFirstChild("Head") then
					local v84 = v_u_3.Sound.Play
					local v85 = {
						["Volume"] = 0.85,
						["Replicate"] = true,
						["ReplicationProperties"] = nil,
						["ReplicationProperties"] = {
							["Instance"] = nil,
							["Volume"] = 0.35,
							["Instance"] = v_u_2.Character.Head
						}
					}
					v84("Chest6Open", v85)
				end
			end
		end
	end
end
