				p_u_98:Destroy()
				v_u_3.Events.RequestPickFlower:InvokeServer(p_u_98)
			end)
			return true
		end
		if p_u_98:GetAttribute("Diamonds") then
			p_u_98:SetAttribute("QueuedToTake", true)
			task.spawn(function()
				-- upvalues: (ref) v_u_3, (copy) p_u_98
