			end)
			v_u_3.Events.RequestTakeDiamonds:FireServer(p_u_98)
			p_u_98:Destroy()
			return true
		end
		if p_u_98:GetAttribute("Interaction") == "HalloweenCandy" then
			p_u_98:SetAttribute("QueuedToTake", true)
			v_u_3.CandyClient.TakeClient(p_u_98)
