function GetSunDialTime() -- name: GetSunDialTime
	local v22 = workspace:GetAttribute("SecondsLeft")
	local v23 = workspace:GetAttribute("State")
	if v22 > 0 then
		local v24 = v22 / 60
		local v25 = math.floor(v24)
		local v26 = v22 - v25 * 60
		local v27 = string.format("%01im %02is", v25, v26)
		if v23 == "Day" then
			return "Sundial - night in " .. v27
		else
			return "Sundial - day in " .. v27
		end
	else
		return v23 == "Night" and "Sundial - becoming night" or "Sundial - becoming day"
	end
end
