function v_u_1.Activate(p165) -- name: Activate
	if p165.State == "Idle" then
		if time() >= p165.LastCast + p165.Cooldown then
			p165.LastCast = time()
			p165:Cast()
		end
	elseif p165.State == "Casting" then
		if time() >= p165.LastCast + p165.Cooldown then
			p165.LastCast = time()
			p165:Reel()
		end
	else
		if p165.State == "Fishing" then
			if p165.HookedItem then
				p165:Pull()
				return
			end
			if time() < p165.LastCast + p165.Cooldown then
				return
			end
			p165.LastCast = time()
			p165:Reel()
		end
		return
	end
end
